import React from "react";
import "./HeroServices.css"; // Import the custom CSS

const HeroServices = () => {
  return (
    <div className="w-full h-auto mx-auto flex flex-col justify-start items-center">
      <h1 className="text-[170px] text-center font-black uppercase tracking-widest bg-gradient-to-b from-white/15 to-transparent bg-clip-text text-transparent">
        Our Services
      </h1>
      <div className="relative neon-wrapper w-[180px] mx-auto h-[50px] -mt-[73px] rounded-full text-[22px] font-bold text-center flex justify-center items-center bg-black z-10">
        <span className="relative z-10 text-white">Our Services</span>
      </div>
    </div>
  );
};

export default HeroServices;
